import{_ as a,o,c as r,a0 as t}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"ADR-0021: Federated Architecture (Local-First + Remote Sync) via Supabase","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0021-federated-architecture-supabase.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0021-federated-architecture-supabase.md","lastUpdated":1783623176000}'),i={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0021-federated-architecture-supabase.md"};function s(n,e,d,l,c,u){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-0021-federated-architecture-local-first-remote-sync-via-supabase" tabindex="-1">ADR-0021: Federated Architecture (Local-First + Remote Sync) via Supabase <a class="header-anchor" href="#adr-0021-federated-architecture-local-first-remote-sync-via-supabase" aria-label="Permalink to &quot;ADR-0021: Federated Architecture (Local-First + Remote Sync) via Supabase&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Proposed</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Atualmente, o NEXUS opera como um ambiente estritamente local (stateful e isolado). O ecossistema é formado por <code>nexus_engine</code>, <code>PostgreSQL</code>, <code>Qdrant</code>, e <code>Ollama</code> gerenciados localmente (via Podman/Docker Compose). Embora a abordagem atual garanta latência sub-milissegundo (<code>&amp;lt; 1ms</code>) e privacidade total dos dados (zero vazamento de IP da empresa para modelos fechados), ela apresenta um limitador crítico: <strong>a incapacidade de compartilhar inteligência e memória contextual entre diferentes agentes/desenvolvedores do time</strong>.</p><p>Para resolver o problema da inteligência coletiva e transformar o NEXUS em um ecossistema estilo &quot;Agent Hive&quot; sem perder os benefícios de latência/segurança para código não publicado, propomos uma arquitetura federada.</p><h2 id="decision-drivers" tabindex="-1">Decision Drivers <a class="header-anchor" href="#decision-drivers" aria-label="Permalink to &quot;Decision Drivers&quot;">​</a></h2><ul><li><strong>Inteligência Coletiva (Agent Hive):</strong> Necessidade de agentes de IA em máquinas distintas compartilharem um grafo semântico central de metadados, soluções e estrutura de código.</li><li><strong>Privacidade do Código-Fonte (Local-First):</strong> Código em elaboração, chaves locais e rascunhos devem permanecer no grafo local (Local Node).</li><li><strong>Consolidação Operacional:</strong> Reduzir a carga de containers locais que o desenvolvedor precisa rodar na própria máquina.</li><li><strong>Complexidade do Stack Vetorial:</strong> Manter PostgreSQL e Qdrant separadamente exige maior custo de gerenciamento do que unificar vetores e relações.</li></ul><h2 id="considered-options" tabindex="-1">Considered Options <a class="header-anchor" href="#considered-options" aria-label="Permalink to &quot;Considered Options&quot;">​</a></h2><h3 id="option-1-manter-estritamente-local" tabindex="-1">Option 1: Manter estritamente Local <a class="header-anchor" href="#option-1-manter-estritamente-local" aria-label="Permalink to &quot;Option 1: Manter estritamente Local&quot;">​</a></h3><ul><li><strong>Pros</strong>: Zero rede; latência máxima de leitura; segurança total do IP.</li><li><strong>Cons</strong>: Agentes são incapazes de aprender uns com os outros; retrabalho na descoberta de caminhos T4 para cada membro do time.</li></ul><h3 id="option-2-migrar-tudo-para-cloud-supabase-total" tabindex="-1">Option 2: Migrar Tudo para Cloud (Supabase Total) <a class="header-anchor" href="#option-2-migrar-tudo-para-cloud-supabase-total" aria-label="Permalink to &quot;Option 2: Migrar Tudo para Cloud (Supabase Total)&quot;">​</a></h3><ul><li><strong>Pros</strong>: Único grafo como single-source-of-truth; stack ultra-simplificado via DBaaS (Supabase pgvector + RLS); excelente interface (Studio).</li><li><strong>Cons</strong>: Latência maior para buscar RAG; tráfego contínuo do código para a nuvem; inabilidade de agentes trabalharem de forma totalmente off-line/privada.</li></ul><h3 id="option-3-federacao-local-first-remote-sync-supabase" tabindex="-1">Option 3: Federação Local-First + Remote Sync (Supabase) <a class="header-anchor" href="#option-3-federacao-local-first-remote-sync-supabase" aria-label="Permalink to &quot;Option 3: Federação Local-First + Remote Sync (Supabase)&quot;">​</a></h3><ul><li><strong>Pros</strong>: Retém a privacidade na ponta via grafo local (SQLite/Postgres local) para código não-commitado. Constrói um <em>Hive</em> remoto para a <code>main</code> e &quot;Reflections&quot; T5.</li><li><strong>Cons</strong>: Maior complexidade arquitetural no MCP para rotear consultas <code>nexus_query</code> em paralelo; necessita de lógica de sync (Rehydration/WebSockets).</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We will adote <strong>Option 3: Federação Local-First + Remote Sync (Supabase)</strong>. O NEXUS adotará uma estratégia de dois nós:</p><ol><li><strong>Edge/Local Node</strong>: Motor RAG rodando no host local indexando <code>drafts</code> e <code>uncommitted changes</code>.</li><li><strong>Cloud/Global Node (Supabase)</strong>: Instância compartilhada contendo a &quot;Memória Institucional&quot; indexada via CI/CD a partir de branches principais, com arestas (Edges) que podem ser herdadas pelo grafo local.</li></ol><p>Como primeiro passo, utilizaremos Supabase com <code>pgvector</code> e migraremos progressivamente as relações mantidas isoladamente entre Qdrant/Postgres para simplificar o motor no cenário remoto.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Para alcançar o potencial máximo de uma <em>Hive</em> de Agentes, eles devem operar em uma memória distribuída. Supabase fornece as ferramentas out-of-the-box (<code>pgvector</code>, <code>Realtime</code>, <code>Edge Functions</code> e <code>RLS</code>) para transformar o banco de dados em um <em>Message Bus</em> semântico para Agentes. Adotando um Roteamento Híbrido, protegemos os <code>drafts</code> na máquina do desenvolvedor enquanto consumimos as sabedorias passadas do repositório remoto.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li><strong>Agentes colaborativos</strong>: Respostas passadas, links T4 e bridges semânticos criados remotamente são consultáveis por todo o time.</li><li><strong>Simplicidade do Compose Remoto</strong>: Redução de infraestrutura para o nó central. Supabase unifica vetores e relacionamentos relacionais.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>O roteador de buscas <code>nexus_query</code> precisará tratar falhas parciais (timeout no Supabase não pode quebrar a busca local).</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li><strong>Resolução de Conflitos T4</strong>: Um nó T4 local que foi excluído, mas o T4 remoto aponta para ele. Necessidade de Edge verification.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation Notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation Notes&quot;">​</a></h2><h3 id="roadmap-de-execucao-iterada" tabindex="-1">Roadmap de Execução Iterada <a class="header-anchor" href="#roadmap-de-execucao-iterada" aria-label="Permalink to &quot;Roadmap de Execução Iterada&quot;">​</a></h3><p><strong>Fase 1: Preparação do Motor (Spike)</strong></p><ul><li>Implementar interface <code>StorageAdapter</code> no Rust Engine.</li><li>Isolar as chamadas SQL e chamadas ao Qdrant.</li></ul><p><strong>Fase 2: Conector Supabase &amp; Roteamento Híbrido</strong></p><ul><li>Levantar nó Supabase para testes e injetar modelo &quot;T4 Graph&quot; usando <code>pgvector</code>.</li><li>Modificar o <code>nexus_query</code> no MCP para realizar <strong>Fan-out</strong>: Consulta banco local + consulta Supabase.</li><li>Fazer deduplicação (<code>chunk_id</code>) no Coordinator, prevalecendo a versão Local.</li></ul><p><strong>Fase 3: Cross-Graph Edges e Subscrições</strong></p><ul><li>Permitir arestas (<code>depends_on:imports</code>, <code>part_of</code>) entre o Local File Node e um Remote Chunk.</li><li>Implementar client de <code>supabase-realtime</code> no Engine para invalidar caches locais quando ocorrer um commit na <code>main</code>.</li></ul><h2 id="related-decisions" tabindex="-1">Related Decisions <a class="header-anchor" href="#related-decisions" aria-label="Permalink to &quot;Related Decisions&quot;">​</a></h2><ul><li>ADR-0010: Abstraction levels and time (Temporalidade e versões devem suportar a noção de &quot;Local&quot; e &quot;Canonical&quot;)</li><li>ADR-0016: CLI Independent Universal MCP</li><li>ADR-0015: Agent Stigmergy &amp; Triangulation</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Supabase pgvector documentation</li><li>Agent Hive Patterns</li></ul>',40)])])}const h=a(i,[["render",s]]);export{p as __pageData,h as default};
